// --- types.d.ts ---
// types.d.ts

/**
 * Weather Card Component - Type Definitions
 */

/**
 * Forecast day item
 */
export interface ForecastDay {
  day: string;      // e.g., "Mon", "Tue"
  icon: string;     // emoji or icon string, e.g., "☀️", "⛅", "🌧️"
  high: number;     // high temperature
  low: number;      // low temperature
}

/**
 * Main component props
 */
export interface Props {
  city: string;           // City name, e.g., "Tokyo"
  temperature: number;    // Current temperature value
  condition: string;      // Weather condition, e.g., "Sunny", "Cloudy", "Rainy"
  humidity: number;       // Humidity percentage (0-100)
  windSpeed: number;      // Wind speed (numeric value)
  unit?: string;          // Temperature unit: "C" or "F" (default: "C")
  forecast: ForecastDay[]; // Array of 5-day forecast items
}

/**
 * Hook return type
 */
export interface HookReturn {
  displayTemperature: string;      // Formatted temperature with unit
  conditionIcon: string;           // Icon/emoji for current condition
  humidityLabel: string;           // "Humidity" + percentage
  windLabel: string;               // "Wind" + speed + unit
}

/**
 * Current weather display sub-component props
 */
export interface CurrentWeatherProps {
  city: string;
  temperature: string;
  condition: string;
  conditionIcon: string;
}

/**
 * Weather details (humidity, wind) sub-component props
 */
export interface WeatherDetailsProps {
  humidity: number;
  windSpeed: number;
  humidityLabel: string;
  windLabel: string;
}

/**
 * Forecast day card sub-component props
 */
export interface ForecastDayProps {
  day: string;
  icon: string;
  high: number;
  low: number;
}

/**
 * Forecast strip sub-component props
 */
export interface ForecastStripProps {
  forecast: ForecastDay[];
}


// --- constants.ts ---
// constants.ts

/**
 * Weather condition to icon/emoji mapping
 * Maps weather condition names to their corresponding emoji representations
 */
export const WEATHER_CONDITION_MAP: Record<string, string> = {
  "Sunny": "☀️",
  "Cloudy": "☁️",
  "Rainy": "🌧️",
  "Snowy": "❄️",
  "Stormy": "⛈️",
  "Partly Cloudy": "⛅",
  "Foggy": "🌫️",
  "Windy": "💨",
};

/** Default temperature unit (Celsius) */
export const DEFAULT_UNIT: string = "C";


// --- hooks.ts ---
// hooks.ts
import { Props, HookReturn } from './types';

/**
 * Mapping of weather conditions to emoji/icon representations
 */
const CONDITION_TO_ICON: Record<string, string> = {
  sunny: '☀️',
  clear: '☀️',
  cloudy: '☁️',
  'partly cloudy': '⛅',
  overcast: '☁️',
  rainy: '🌧️',
  rain: '🌧️',
  thunderstorm: '⛈️',
  stormy: '⛈️',
  snowy: '❄️',
  snow: '❄️',
  foggy: '🌫️',
  fog: '🌫️',
  windy: '💨',
};

/**
 * Custom hook to process weather data and return formatted display strings
 * @param props - Weather card props containing temperature, condition, humidity, and wind data
 * @returns Object containing formatted display strings for the weather card
 */
export function useWeatherCard(props: Props): HookReturn {
  const {
    temperature,
    unit = 'C',
    condition,
    humidity,
    windSpeed,
  } = props;

  // 1. Format temperature with unit
  const displayTemperature = formatTemperature(temperature, unit);

  // 2. Map condition to icon
  const conditionIcon = mapConditionToIcon(condition);

  // 3. Format humidity label
  const humidityLabel = formatHumidityLabel(humidity);

  // 4. Format wind label
  const windLabel = formatWindLabel(windSpeed, unit);

  return {
    displayTemperature,
    conditionIcon,
    humidityLabel,
    windLabel,
  };
}

/**
 * Format temperature with unit symbol
 */
function formatTemperature(temperature: number, unit: string): string {
  if (typeof temperature !== 'number' || !Number.isFinite(temperature)) {
    return 'N/A';
  }
  return `${temperature}°${unit}`;
}

/**
 * Map weather condition to emoji icon
 */
function mapConditionToIcon(condition: string): string {
  if (typeof condition !== 'string') {
    return '🌤️';
  }
  const lowerCondition = condition.toLowerCase();
  return CONDITION_TO_ICON[lowerCondition] || '🌤️';
}

/**
 * Format humidity label with validation
 */
function formatHumidityLabel(humidity: number): string {
  if (typeof humidity !== 'number' || !Number.isFinite(humidity)) {
    return 'Humidity N/A';
  }
  if (humidity < 0 || humidity > 100) {
    return 'Humidity N/A';
  }
  const roundedHumidity = Math.round(humidity);
  return `Humidity ${roundedHumidity}%`;
}

/**
 * Format wind label with speed unit based on temperature unit
 */
function formatWindLabel(windSpeed: number, unit: string): string {
  if (typeof windSpeed !== 'number' || !Number.isFinite(windSpeed)) {
    return 'Wind N/A';
  }
  const speedUnit = unit === 'F' ? 'mph' : 'km/h';
  const roundedSpeed = Math.round(windSpeed * 10) / 10;
  return `Wind ${roundedSpeed} ${speedUnit}`;
}


