import { Stack, Text, Heading } from '@ggui-ai/design/primitives';
import { CurrentWeatherProps } from './types';

export const CurrentWeather = ({
  city,
  temperature,
  condition,
  conditionIcon,
}: CurrentWeatherProps) => {
  return (
    <Stack gap={8} align="stretch">
      {/* City Name */}
      <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {city}
      </Text>

      {/* Temperature and Icon Row */}
      <Stack direction="horizontal" gap={16} align="center">
        <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
          {temperature}
        </Heading>
        <Text size="3xl" color="var(--ggui-color-onSurface, #18181b)">
          {conditionIcon}
        </Text>
      </Stack>

      {/* Condition Text */}
      <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {condition}
      </Text>
    </Stack>
  );
};

