import React from 'react';
import { Stack, Box, Text, Divider } from '@ggui-ai/design/primitives';
import type { WeatherDetailsProps } from './types';

/**
 * WeatherDetails Component
 * 
 * Displays humidity percentage and wind speed in a side-by-side layout.
 * Part of the weather card sub-component structure.
 */
export function Component(props: WeatherDetailsProps): React.ReactElement {
  const { humidity, windSpeed, humidityLabel, windLabel } = props;

  return (
    <Stack
      direction="horizontal"
      gap={16}
      align="center"
      justify="start"
    >
      {/* Humidity Section */}
      <Box>
        <Text
          variant="bodySmall"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {humidityLabel}
        </Text>
      </Box>

      {/* Divider */}
      <Divider orientation="vertical" margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

      {/* Wind Speed Section */}
      <Box>
        <Text
          variant="bodySmall"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {windLabel}
        </Text>
      </Box>
    </Stack>
  );
}


