import React from 'react';
import { Card, Stack, Text, Spacer } from '@ggui-ai/design/primitives';
import type { ForecastDayProps } from '../types';

/**
 * ForecastDay - Renders a single day forecast card
 * Displays day name, weather icon, and temperature range (high/low)
 */
export const ForecastDay: React.FC<ForecastDayProps> = ({ day, icon, high, low }) => {
  return (
    <Card
      padding={8}
      shadow="none"
      border={true}
      radius="md"
      style={{
        textAlign: 'center',
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        transition: 'background-color 200ms ease-in-out',
      }}
      onMouseEnter={(e) => {
        (e.currentTarget as HTMLElement).style.backgroundColor =
          'var(--ggui-color-primary-50, #f0f9ff)';
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLElement).style.backgroundColor =
          'var(--ggui-color-surfaceVariant, #f4f4f5)';
      }}
    >
      <Stack gap={4} align="center" direction="vertical">
        {/* Day name */}
        <Text
          variant="label"
          color="var(--ggui-color-onSurface, #18181b)"
          size="sm"
        >
          {day}
        </Text>

        <Spacer size={4} />

        {/* Weather icon */}
        <div
          style={{
            fontSize: '24px',
            lineHeight: 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          {icon}
        </div>

        <Spacer size={4} />

        {/* Temperature range */}
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          <span style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}>H: {high}°</span>
          {' '}
          <span style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>L: {low}°</span>
        </Text>
      </Stack>
    </Card>
  );
};


