import { Container, Stack } from '@ggui-ai/design/primitives';
import { ForecastDay } from './ForecastDay';
import { ForecastStripProps } from '../types';

export const ForecastStrip: React.FC<ForecastStripProps> = ({ forecast }) => {
  return (
    <Container
      maxWidth="full"
      padding={0}
    >
      <Stack
        direction="horizontal"
        justify="evenly"
        align="center"
        gap={`var(--ggui-spacing-2, 8px)`}
      >
        {forecast.map((day, index) => (
          <ForecastDay key={index} day={day.day} icon={day.icon} high={day.high} low={day.low} />
        ))}
      </Stack>
    </Container>
  );
};


