// ui.tsx
import React from 'react';
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';
import { useWeatherCard } from './hook';
import { CurrentWeather } from './components';
import { WeatherDetails } from './components';
import { ForecastStrip } from './components';
import type { Props } from './types';

/**
 * WeatherCard Component
 * 
 * A comprehensive weather display card that shows current conditions,
 * detailed weather metrics (humidity, wind speed), and a 5-day forecast.
 * 
 * @param props - Weather data and configuration
 * @returns A fully styled weather card component
 */
export default function WeatherCard(props: Props): JSX.Element {
  // Transform props into displayable values using the custom hook
  const { displayTemperature, conditionIcon, humidityLabel, windLabel } =
    useWeatherCard(props);

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={24} direction="vertical">
        {/* Current Weather Section */}
        <CurrentWeather
          city={props.city}
          temperature={displayTemperature}
          condition={props.condition}
          conditionIcon={conditionIcon}
        />

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin={16}
          color="var(--ggui-color-outlineVariant, #e4e4e7)"
        />

        {/* Weather Details Section */}
        <WeatherDetails
          humidity={props.humidity}
          windSpeed={props.windSpeed}
          humidityLabel={humidityLabel}
          windLabel={windLabel}
        />

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin={16}
          color="var(--ggui-color-outlineVariant, #e4e4e7)"
        />

        {/* Forecast Strip Section */}
        <ForecastStrip forecast={props.forecast} />
      </Stack>
    </Card>
  );
}

